fn main() {
    // Match libghostty's minimum deployment target to avoid linker warnings
    println!("cargo:REDACTED.0");

    tauri_build::build();

    // Link libghostty and required macOS frameworks
    let vendor_dir = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("vendor")
        .join("ghostty");

    println!("cargo:rustc-link-search=native={}", vendor_dir.display());
    println!("cargo:rustc-link-lib=static=ghostty");

    // C++ standard library required by glslang (shader compiler) in libghostty
    println!("cargo:rustc-link-lib=c++");

    // macOS frameworks required by libghostty's Metal renderer
    println!("cargo:rustc-link-lib=framework=Metal");
    println!("cargo:rustc-link-lib=framework=MetalKit");
    println!("cargo:rustc-link-lib=framework=AppKit");
    println!("cargo:rustc-link-lib=framework=QuartzCore");
    println!("cargo:rustc-link-lib=framework=CoreGraphics");
    println!("cargo:rustc-link-lib=framework=IOSurface");
    println!("cargo:rustc-link-lib=framework=Foundation");

    // Rerun if the static library changes
    println!("cargo:rerun-if-changed=vendor/ghostty/libghostty.a");
    println!("cargo:rerun-if-changed=vendor/ghostty/ghostty.h");
}

