  2→ * Ghostty Embedding API
  3→ *
  4→ * Minimal header for libghostty FFI from GhosttyKit.xcframework.
  5→ * Build from source: https://github.com/manaflow-ai/ghostty
  6→ *   zig build -Demit-xcframework=true -Dxcframework-target=universal -Doptimize=ReleaseFast
  7→ *
  8→ * Copy libghostty.a from GhosttyKit.xcframework/macos-arm64_x86_64/ into this directory.
  9→ */
 10→
 11→#ifndef GHOSTTY_H
 12→#define GHOSTTY_H
 13→
 14→#include <stdbool.h>
 15→#include <stddef.h>
 16→#include <stdint.h>
 17→
