 27→typedef void* ghostty_inspector_t;
 28→
 29→/* ---------- Enums ---------- */
 30→
 31→typedef enum {
 32→    GHOSTTY_PLATFORM_MACOS = 0,
 33→    GHOSTTY_PLATFORM_IOS = 1,
 34→} ghostty_platform_e;
 35→
