 54→    GHOSTTY_MOUSE_BUTTON_RIGHT = 1,
 55→    GHOSTTY_MOUSE_BUTTON_MIDDLE = 2,
 56→} ghostty_input_mouse_button_e;
 57→
 58→typedef enum {
 59→    GHOSTTY_MODS_NONE = 0,
 60→    GHOSTTY_MODS_SHIFT = 1 << 0,
 61→    GHOSTTY_MODS_CTRL = 1 << 1,
