133→);
134→
135→/* ---------- Config structs ---------- */
136→
137→typedef struct {
138→    void* userdata;
139→    bool supports_selection_clipboard;
140→    ghostty_runtime_wakeup_cb wakeup_cb;
141→    ghostty_runtime_action_cb action_cb;
142→    ghostty_runtime_read_clipboard_cb read_clipboard_cb;
143→    ghostty_runtime_confirm_read_clipboard_cb confirm_read_clipboard_cb;
144→    ghostty_runtime_write_clipboard_cb write_clipboard_cb;
