146→} ghostty_runtime_config_s;
147→
148→typedef union {
149→    void* nsview; /* macOS: NSView* */
150→    void* uiview; /* iOS: UIView* */
151→} ghostty_platform_u;
152→
153→typedef struct {
154→    ghostty_platform_e platform_tag;
155→    ghostty_platform_u platform;
156→    void* userdata;
157→    double scale_factor;
158→    float font_size;
159→    const char* working_directory;
160→    const char* command;
161→    ghostty_env_var_s* env_vars;
162→    size_t env_var_count;
163→    const char* initial_input;
164→    bool wait_after_command;
165→    ghostty_surface_context_e context;
166→} ghostty_surface_config_s;
167→
168→/* ---------- Lifecycle ---------- */
169→
170→int ghostty_init(uintptr_t argc, char** argv);
171→
172→ghostty_config_t ghostty_config_new(void);
173→void ghostty_config_load_default_files(ghostty_config_t config);
174→void ghostty_config_load_file(ghostty_config_t config, const char* path);
175→void ghostty_config_finalize(ghostty_config_t config);
176→void ghostty_config_free(ghostty_config_t config);
177→void ghostty_config_set(ghostty_config_t config, const char* key, const char* value);
178→
179→ghostty_app_t ghostty_app_new(
180→    const ghostty_runtime_config_s* runtime_config,
181→    ghostty_config_t config
182→);
183→void ghostty_app_free(ghostty_app_t app);
184→bool ghostty_app_tick(ghostty_app_t app);
185→
186→/* ---------- Surface ---------- */
187→
188→ghostty_surface_t ghostty_surface_new(
189→    ghostty_app_t app,
190→    const ghostty_surface_config_s* config
191→);
192→void ghostty_surface_free(ghostty_surface_t surface);
193→
194→void ghostty_surface_draw(ghostty_surface_t surface);
195→void ghostty_surface_set_size(ghostty_surface_t surface, uint32_t width, uint32_t height);
196→void ghostty_surface_set_focus(ghostty_surface_t surface, bool focused);
197→
198→bool ghostty_surface_key(ghostty_surface_t surface, ghostty_input_key_s key);
199→void ghostty_surface_text(ghostty_surface_t surface, const char* text, size_t len);
200→
201→bool ghostty_surface_mouse_button(
202→    ghostty_surface_t surface,
203→    ghostty_input_mouse_state_e state,
204→    ghostty_input_mouse_button_e button,
205→    ghostty_input_mods_e mods
206→);
207→void ghostty_surface_mouse_pos(
208→    ghostty_surface_t surface,
209→    double x,
210→    double y,
211→    ghostty_input_mods_e mods
212→);
213→void ghostty_surface_mouse_scroll(
214→    ghostty_surface_t surface,
215→    double dx,
216→    double dy,
217→    ghostty_input_scroll_mods_t mods
218→);
219→
220→#ifdef __cplusplus
221→}
222→#endif
223→
224→#endif /* GHOSTTY_H */
