 41→fn mods_from_event(event: &NSEvent) -> GhosttyInputMods {
 42→    let flags = event.modifierFlags();
 43→    let mut mods = GhosttyInputMods::NONE;
 44→
 45→    if flags.contains(NSEventModifierFlags::Shift) {
 46→        mods |= GhosttyInputMods::SHIFT;
 47→    }
 48→    if flags.contains(NSEventModifierFlags::Control) {
 49→        mods |= GhosttyInputMods::CTRL;
 50→    }
 51→    if flags.contains(NSEventModifierFlags::Option) {
 52→        mods |= GhosttyInputMods::ALT;
 53→    }
 54→    if flags.contains(NSEventModifierFlags::Command) {
 55→        mods |= GhosttyInputMods::SUPER;
 56→    }
 57→
 58→    mods
 59→}
 60→
 61→fn consumed_mods_for_event(surface: *mut c_void, event: &NSEvent) -> GhosttyInputMods {
 62→    let translated =
 63→        unsafe { super::ghostty_surface_key_translation_mods(surface, mods_from_event(event)) };
 64→    let mut consumed = GhosttyInputMods::NONE;
 65→
 66→    if translated.contains(GhosttyInputMods::SHIFT) {
 67→        consumed |= GhosttyInputMods::SHIFT;
 68→    }
 69→    if translated.contains(GhosttyInputMods::ALT) {
 70→        consumed |= GhosttyInputMods::ALT;
 71→    }
 72→
 73→    consumed
 74→}
 75→
 76→fn text_for_key_event(event: &NSEvent) -> Option<String> {
 77→    let chars = event.characters()?.to_string();
 78→    if chars.is_empty() {
 79→        return None;
 80→    }
 81→
 82→    if chars.chars().count() == 1 {
 83→        let scalar = chars.chars().next()? as u32;
 84→        if scalar < 0x20
 85→            && event
 86→                .modifierFlags()
 87→                .contains(NSEventModifierFlags::Control)
 88→        {
 89→            return event
 90→                .charactersIgnoringModifiers()
 91→                .map(|text| text.to_string());
 92→        }
 93→        if (0xF700..=0xF8FF).contains(&scalar) {
 94→            return None;
 95→        }
 96→    }
 97→
 98→    Some(chars)
 99→}
100→
101→fn should_send_text(text: &str) -> bool {
102→    match text.chars().next() {
103→        Some(ch) => (ch as u32) >= 0x20,
104→        None => false,
105→    }
106→}
107→
108→fn unshifted_codepoint_from_event(event: &NSEvent) -> u32 {
109→    event
110→        .charactersIgnoringModifiers()
111→        .or_else(|| event.characters())
112→        .and_then(|text| text.to_string().chars().next())
113→        .map(|ch| ch as u32)
114→        .unwrap_or(0)
115→}
116→
117→fn matches_command_shortcut(event: &NSEvent, key: char) -> bool {
118→    let flags = event.modifierFlags();
119→    if !flags.contains(NSEventModifierFlags::Command) {
120→        return false;
121→    }
122→    if flags.contains(NSEventModifierFlags::Control) || flags.contains(NSEventModifierFlags::Option)
123→    {
124→        return false;
125→    }
126→
127→    event
128→        .charactersIgnoringModifiers()
129→        .map(|text| text.to_string())
130→        .map(|text| text.eq_ignore_ascii_case(&key.to_string()))
131→        .unwrap_or(false)
132→}
133→
134→fn paste_clipboard_text(surface: *mut c_void) -> bool {
135→    let Some(text) = super::system_clipboard_text().filter(|text| !text.is_empty()) else {
136→        return false;
137→    };
138→
139→    let c_text = CString::new(text.as_str()).unwrap_or_default();
140→    unsafe {
141→        super::ghostty_surface_text(surface, c_text.as_ptr(), text.len());
142→    }
143→    true
144→}
145→
146→fn send_key_event(surface: *mut c_void, event: &NSEvent) -> bool {
147→    let mut key = GhosttyInputKey {
148→        action: if event.isARepeat() {
149→            GhosttyInputAction::Repeat
150→        } else {
151→            GhosttyInputAction::Press
152→        },
153→        mods: mods_from_event(event),
154→        consumed_mods: consumed_mods_for_event(surface, event),
155→        keycode: event.keyCode() as u32,
156→        text: ptr::null(),
157→        unshifted_codepoint: unshifted_codepoint_from_event(event),
158→        composing: false,
159→    };
160→
161→    if let Some(text) = text_for_key_event(event).filter(|text| should_send_text(text)) {
162→        let c_text = CString::new(text).unwrap_or_default();
163→        key.text = c_text.as_ptr();
164→        unsafe { super::ghostty_surface_key(surface, key) }
165→    } else {
166→        unsafe { super::ghostty_surface_key(surface, key) }
167→    }
168→}
