170→define_class!(
171→    #[unsafe(super(NSView))]
172→    #[thread_kind = MainThreadOnly]
173→    #[ivars = GhosttyHostViewIvars]
174→    #[name = "EntireGhosttyHostView"]
175→    struct GhosttyHostView;
176→
177→    impl GhosttyHostView {
178→        #[unsafe(method(acceptsFirstResponder))]
179→        fn accepts_first_responder(&self) -> bool {
180→            true
181→        }
182→
183→        #[unsafe(method(becomeFirstResponder))]
184→        fn become_first_responder(&self) -> bool {
185→            let result: bool = unsafe { msg_send![super(self), becomeFirstResponder] };
186→            if result {
187→                let surface = self.surface();
188→                if !surface.is_null() {
189→                    unsafe { super::ghostty_surface_set_focus(surface, true) };
190→                }
191→            }
192→            result
193→        }
194→
195→        #[unsafe(method(resignFirstResponder))]
196→        fn resign_first_responder(&self) -> bool {
197→            let result: bool = unsafe { msg_send![super(self), resignFirstResponder] };
198→            if result {
199→                let surface = self.surface();
200→                if !surface.is_null() {
201→                    unsafe { super::ghostty_surface_set_focus(surface, false) };
202→                }
203→            }
204→            result
205→        }
206→
207→        #[unsafe(method(mouseDown:))]
208→        fn mouse_down(&self, event: &NSEvent) {
209→            if let Some(window) = self.window() {
210→                let _: bool = unsafe { msg_send![&*window, makeFirstResponder: self] };
211→            }
212→
213→            let surface = self.surface();
214→            if !surface.is_null() {
215→                let point = self.convertPoint_fromView(event.locationInWindow(), None);
216→                let y = self.bounds().size.height - point.y;
217→                let mods = mods_from_event(event);
218→                unsafe {
219→                    super::ghostty_surface_mouse_pos(surface, point.x, y, mods);
220→                    let _ = super::ghostty_surface_mouse_button(
221→                        surface,
222→                        GhosttyMouseState::Press,
223→                        GhosttyMouseButton::Left,
224→                        mods,
225→                    );
226→                }
227→            } else {
228→                unsafe { msg_send![super(self), mouseDown: event] }
229→            }
230→        }
231→
232→        #[unsafe(method(mouseUp:))]
233→        fn mouse_up(&self, event: &NSEvent) {
234→            let surface = self.surface();
235→            if !surface.is_null() {
236→                let mods = mods_from_event(event);
237→                unsafe {
238→                    let _ = super::ghostty_surface_mouse_button(
239→                        surface,
240→                        GhosttyMouseState::Release,
241→                        GhosttyMouseButton::Left,
242→                        mods,
243→                    );
244→                }
245→            } else {
246→                unsafe { msg_send![super(self), mouseUp: event] }
247→            }
248→        }
249→
250→        #[unsafe(method(scrollWheel:))]
251→        fn scroll_wheel(&self, event: &NSEvent) {
252→            let surface = self.surface();
253→            if !surface.is_null() {
254→                if let Some(window) = self.window() {
255→                    let _: bool = unsafe { msg_send![&*window, makeFirstResponder: self] };
256→                }
257→
258→                let point = self.convertPoint_fromView(event.locationInWindow(), None);
259→                let y = self.bounds().size.height - point.y;
260→                let mods = mods_from_event(event);
261→                let scroll_mods = GhosttyScrollMods {
262→                    precision: event.hasPreciseScrollingDeltas(),
263→                };
264→
265→                unsafe {
266→                    super::ghostty_surface_set_focus(surface, true);
267→                    super::ghostty_surface_mouse_pos(surface, point.x, y, mods);
268→                    super::ghostty_surface_mouse_scroll(
269→                        surface,
270→                        event.scrollingDeltaX(),
271→                        event.scrollingDeltaY(),
272→                        scroll_mods,
273→                    );
274→                }
275→            } else {
276→                unsafe { msg_send![super(self), scrollWheel: event] }
277→            }
278→        }
279→
280→        #[unsafe(method(keyDown:))]
281→        fn key_down(&self, event: &NSEvent) {
282→            let surface = self.surface();
283→            if !surface.is_null() {
284→                unsafe { super::ghostty_surface_set_focus(surface, true) };
285→                if matches_command_shortcut(event, 'v') && paste_clipboard_text(surface) {
286→                    debug_log("ghostty_host_view: handled command+v via system pasteboard");
287→                    return;
288→                }
289→                let handled = send_key_event(surface, event);
290→                let text = event
291→                    .characters()
292→                    .map(|chars| chars.to_string())
293→                    .unwrap_or_default();
294→                debug_log(&format!(
295→                    "ghostty_host_view: keyDown keyCode={} handled={} chars={:?}",
296→                    event.keyCode(),
297→                    handled,
298→                    text,
299→                ));
300→                if handled {
301→                    return;
302→                }
303→            }
304→
305→            unsafe { msg_send![super(self), keyDown: event] }
306→        }
307→
308→        #[unsafe(method(paste:))]
309→        fn paste(&self, _sender: Option<&AnyObject>) {
310→            let surface = self.surface();
311→            if !surface.is_null() {
312→                unsafe { super::ghostty_surface_set_focus(surface, true) };
313→                let _ = paste_clipboard_text(surface);
314→            }
315→        }
316→
317→        #[unsafe(method(doCommandBySelector:))]
318→        fn do_command_by_selector(&self, _selector: Sel) {
319→            // Prevent NSBeep for commands we intentionally leave to Ghostty.
320→        }
321→    }
322→);
