  7→/// Append a debug line to /tmp/entire-terminal-debug.log
  8→fn debug_log(msg: &str) {
  9→    use std::io::Write;
 10→    let timestamp = std::time::SystemTime::now()
 11→        .duration_since(std::time::UNIX_EPOCH)
 12→        .unwrap_or_default();
 13→    let line = format!(
 14→        "[{}.{:03}] {}\n",
 15→        timestamp.as_secs(),
 16→        timestamp.subsec_millis(),
 17→        msg
 18→    );
 19→    if let Ok(mut f) = std::fs::OpenOptions::new()
 20→        .create(true)
 21→        .append(true)
 22→        .open("/tmp/entire-terminal-debug.log")
 23→    {
 24→        let _ = f.write_all(line.as_bytes());
 25→    }
 26→}
