 36→fn resolve_surface_command(command: Option<&str>) -> Option<&str> {
 37→    match command {
 38→        Some("claude-code") => Some("claude"),
 39→        Some("codex") => Some("codex"),
 40→        Some("terminal") | None => None,
 41→        Some(other) => Some(other),
 42→    }
