 45→/// Create a new libghostty surface with a native NSView overlay.
 46→///
 47→/// The surface spawns its own PTY internally. If `command` is provided
 48→/// (e.g., "claude" or "codex"), libghostty will run that command instead
 49→/// of the default shell.
 50→#[tauri::command]
 51→pub fn ghostty_create_surface(
 52→    window: WebviewWindow,
 53→    working_dir: String,
 54→    command: Option<String>,
 55→    state: State<'_, Mutex<super::GhosttyState>>,
 56→) -> Result<String, String> {
 57→    debug_log(&format!(
 58→        "ghostty_create_surface called: working_dir={:?}, command={:?}",
 59→        working_dir, command
 60→    ));
 61→
 62→    let mut gs = state.lock().map_err(|e| {
 63→        let msg = format!("State lock error: {}", e);
 64→        debug_log(&msg);
 65→        msg
 66→    })?;
 67→
 68→    // Ensure the ghostty app is initialized
 69→    debug_log("Ensuring ghostty app is initialized...");
 70→    gs.ensure_app().map_err(|e| {
 71→        debug_log(&format!("ensure_app FAILED: {}", e));
 72→        e
 73→    })?;
 74→    if let Some(app) = gs.app.as_ref() {
 75→        app.set_focus(true);
 76→        debug_log("ghostty app focus set true");
 77→    }
 78→    debug_log("ghostty app initialized OK");
 79→
 80→    // Get the native window handle for overlay placement
 81→    debug_log("Getting NSWindow handle...");
 82→    let ns_window = overlay::get_nswindow(&window).map_err(|e| {
 83→        debug_log(&format!("get_nswindow FAILED: {}", e));
 84→        e
 85→    })?;
 86→    debug_log(&format!("NSWindow handle OK: {:?}", ns_window));
 87→
 88→    // Create the native NSView overlay
 89→    debug_log("Creating GhosttyOverlay (NSView + CAMetalLayer)...");
 90→    let overlay = unsafe {
 91→        GhosttyOverlay::new(ns_window).map_err(|e| {
 92→            debug_log(&format!("GhosttyOverlay::new FAILED: {}", e));
 93→            e
 94→        })?
 95→    };
 96→    let nsview_ptr = overlay.nsview_ptr();
 97→    debug_log(&format!("Overlay created OK, nsview_ptr={:?}", nsview_ptr));
 98→
 99→    // Get the window's backing scale factor for Retina displays
100→    let scale_factor = window.scale_factor().unwrap_or(2.0);
101→    debug_log(&format!("scale_factor={}", scale_factor));
102→
103→    // Resolve the command — map agent names to CLI binaries
104→    let resolved_command = resolve_surface_command(command.as_deref());
105→    debug_log(&format!("resolved_command={:?}", resolved_command));
106→
107→    // Create the libghostty surface
108→    debug_log("Creating GhosttySurface (ghostty_surface_new FFI call)...");
109→    let app = gs.app.as_ref().unwrap();
110→    let surface = GhosttySurface::new(
111→        app,
112→        nsview_ptr,
113→        Some(&working_dir),
114→        resolved_command,
115→        scale_factor,
116→    )
117→    .map_err(|e| {
118→        debug_log(&format!("GhosttySurface::new FAILED: {}", e));
119→        e
120→    })?;
121→    overlay.set_surface(surface.raw());
122→    debug_log("GhosttySurface created OK");
123→
124→    let surface_id = generate_surface_id();
125→    gs.surfaces
126→        .insert(surface_id.clone(), SurfaceEntry { surface, overlay });
127→
128→    debug_log(&format!("Surface registered with id={}", surface_id));
129→    Ok(surface_id)
130→}
