104→fn get_transcript(
105→    repo_path: String,
106→    checkpoint_id: String,
107→    session_index: u32,
108→) -> Result<Vec<session::TranscriptMessage>, String> {
109→    let repo = git::open_repo(&repo_path)?;
110→
111→    let prefix = &checkpoint_id[..2];
112→    let suffix = &checkpoint_id[2..];
113→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
114→    let meta_content = read_blob(&repo, &meta_path).ok();
115→    let candidates =
116→        transcript_candidate_paths(&checkpoint_id, session_index, meta_content.as_deref());
117→
118→    for path in &candidates {
119→        if let Ok(content) = read_blob(&repo, path) {
120→            return Ok(session::read_transcript(&content));
121→        }
122→    }
123→
124→    Err(format!("Transcript not found for checkpoint {} session {}", checkpoint_id, session_index))
125→}
126→
127→fn transcript_candidate_paths(
128→    checkpoint_id: &str,
129→    session_index: u32,
130→    meta_content: Option<&str>,
131→) -> Vec<String> {
132→    let prefix = &checkpoint_id[..2];
133→    let suffix = &checkpoint_id[2..];
134→    let requested_session_dir = format!("{}/{}/{}", prefix, suffix, session_index);
135→    let mut candidates = Vec::new();
136→
137→    let mut push_candidate = |path: String| {
138→        if !path.is_empty() && !candidates.contains(&path) {
139→            candidates.push(path);
140→        }
141→    };
142→
143→    if let Some(meta_content) = meta_content {
144→        if let Ok(meta) = serde_json::from_str::<serde_json::Value>(meta_content) {
145→            if let Some(sessions) = meta.get("sessions").and_then(|s| s.as_array()) {
146→                let mut ordered_sessions = Vec::new();
147→                if let Some(session) = sessions.get(session_index as usize) {
148→                    ordered_sessions.push(session);
149→                }
150→                for (idx, session) in sessions.iter().enumerate() {
151→                    if idx != session_index as usize {
152→                        ordered_sessions.push(session);
153→                    }
154→                }
155→
156→                for session in ordered_sessions {
157→                    if let Some(path) = session.get("transcript").and_then(|p| p.as_str()) {
158→                        push_candidate(path.trim_start_matches('/').to_string());
159→                    }
160→                }
161→            }
162→        }
163→    }
164→
165→    push_candidate(format!("{}/full.jsonl", requested_session_dir));
166→    push_candidate(format!("{}/transcript.jsonl", requested_session_dir));
167→    candidates
168→}
