170→/// Read a blob from the entire/checkpoints/v1 branch by path
171→fn read_blob(repo: &git2::Repository, path: &str) -> Result<String, String> {
172→    let branch_ref = repo
173→        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
174→        .map_err(|e| format!("No checkpoint branch: {}", e))?;
175→
176→    let commit = branch_ref
177→        .get()
178→        .peel_to_commit()
179→        .map_err(|e| format!("Failed to peel: {}", e))?;
180→
181→    let tree = commit
182→        .tree()
183→        .map_err(|e| format!("Failed to get tree: {}", e))?;
184→
185→    let entry = tree
186→        .get_path(std::path::Path::new(path))
187→        .map_err(|e| format!("Path not found: {}", e))?;
188→
189→    let blob = repo
190→        .find_blob(entry.id())
191→        .map_err(|e| format!("Failed to read blob: {}", e))?;
192→
193→    std::str::from_utf8(blob.content())
194→        .map(|s| s.to_string())
195→        .map_err(|e| format!("Invalid UTF-8: {}", e))
196→}
