230→#[derive(serde::Serialize)]
231→struct EntireLogResult {
232→    lines: Vec<String>,
233→    total_lines: u32,
234→    file_size_bytes: u64,
235→}
236→
237→#[tauri::command]
238→fn get_entire_logs(repo_path: String, tail_lines: u32) -> Result<EntireLogResult, String> {
239→    let log_path = std::path::Path::new(&repo_path).join(".entire/logs/entire.log");
240→    if !log_path.exists() {
241→        return Err("No log file found".to_string());
242→    }
243→
244→    let metadata = std::fs::metadata(&log_path)
245→        .map_err(|e| format!("Failed to read log metadata: {}", e))?;
246→    let file_size_bytes = metadata.len();
247→
248→    let file = std::fs::File::open(&log_path)
249→        .map_err(|e| format!("Failed to open log file: {}", e))?;
250→
251→    // Count total lines
252→    let reader = BufReader::new(&file);
253→    let all_lines: Vec<String> = reader.lines().filter_map(|l| l.ok()).collect();
254→    let total_lines = all_lines.len() as u32;
255→
256→    // Take last N lines
257→    let start = all_lines.len().saturating_sub(tail_lines as usize);
258→    let lines = all_lines[start..].to_vec();
259→
260→    Ok(EntireLogResult {
261→        lines,
262→        total_lines,
263→        file_size_bytes,
264→    })
265→}
