267→#[tauri::command]
268→fn get_checkpoint_logs(
269→    repo_path: String,
270→    checkpoint_id: String,
271→    session_ids: Vec<String>,
272→) -> Result<EntireLogResult, String> {
273→    let log_path = std::path::Path::new(&repo_path).join(".entire/logs/entire.log");
274→    if !log_path.exists() {
275→        return Ok(EntireLogResult {
276→            lines: Vec::new(),
277→            total_lines: 0,
278→            file_size_bytes: 0,
279→        });
280→    }
281→
282→    let metadata = std::fs::metadata(&log_path)
283→        .map_err(|e| format!("Failed to read log metadata: {}", e))?;
284→    let file_size_bytes = metadata.len();
285→
286→    let file = std::fs::File::open(&log_path)
287→        .map_err(|e| format!("Failed to open log file: {}", e))?;
288→
289→    let reader = BufReader::new(file);
290→    let mut matching_lines = Vec::new();
291→
292→    for line in reader.lines() {
293→        let line = match line {
294→            Ok(l) => l,
295→            Err(_) => continue,
296→        };
297→
298→        // Parse each line as JSON and check for matching session_id or checkpoint_id
299→        if let Ok(value) = serde_json::from_str::<serde_json::Value>(&line) {
300→            let line_session_id = value.get("session_id").and_then(|v| v.as_str());
301→            let line_checkpoint_id = value.get("checkpoint_id").and_then(|v| v.as_str());
302→
303→            let matches = line_session_id
304→                .map(|sid| session_ids.iter().any(|s| s == sid))
305→                .unwrap_or(false)
306→                || line_checkpoint_id
307→                    .map(|cid| cid == checkpoint_id)
308→                    .unwrap_or(false);
309→
310→            if matches {
311→                matching_lines.push(line);
312→            }
313→        }
314→    }
315→
316→    Ok(EntireLogResult {
317→        total_lines: matching_lines.len() as u32,
318→        lines: matching_lines,
319→        file_size_bytes,
320→    })
321→}
