594→fn call_anthropic_semantic_review(prompt: &str) -> Result<String, String> {
595→    let api_key = std::env::var("ANTHROPIC_API_KEY")
596→        .map_err(|_| "ANTHROPIC_API_KEY is not set".to_string())?;
597→    let model = std::env::var("ANTHROPIC_MODEL")
598→        .unwrap_or_else(|_| "claude-sonnet-4-20250514".to_string());
599→
600→    let client = reqwest::blocking::Client::builder()
601→        .timeout(std::time::Duration::from_secs(90))
602→        .build()
603→        .map_err(|e| format!("Failed to build Anthropic client: {}", e))?;
604→
605→    let response = client
606→        .post("https://api.anthropic.com/v1/messages")
607→        .header("x-api-key", api_key)
608→        .header("anthropic-version", "2023-06-01")
609→        .header("content-type", "application/json")
610→        .json(&AnthropicRequest {
611→            model,
612→            max_tokens: 2_000,
613→            temperature: 0.2,
614→            system: "You are reviewing a git diff. Return JSON only with precise, line-linked explanations of the most important changes.".to_string(),
615→            messages: vec![AnthropicMessage {
616→                role: "user".to_string(),
617→                content: prompt.to_string(),
618→            }],
619→        })
620→        .send()
621→        .map_err(|e| format!("Anthropic request failed: {}", e))?
622→        .error_for_status()
623→        .map_err(|e| format!("Anthropic request failed: {}", e))?;
624→
625→    let body: AnthropicResponse = response
626→        .json()
627→        .map_err(|e| format!("Failed to decode Anthropic response: {}", e))?;
628→
629→    let text = body
630→        .content
631→        .into_iter()
632→        .filter(|block| block.kind == "text")
633→        .filter_map(|block| block.text)
634→        .collect::<Vec<_>>()
635→        .join("\n");
636→
637→    if text.trim().is_empty() {
638→        return Err("Anthropic response did not include any text output".to_string());
639→    }
640→
641→    Ok(text)
642→}
