664→#[tauri::command]
665→fn run_checkpoint_semantic_review(
666→    repo_path: String,
667→    checkpoint_id: String,
668→    commit_sha: String,
669→) -> Result<semantic_review::RunCheckpointSemanticReviewResponse, String> {
670→    if checkpoint_id.len() < 2 {
671→        return Err("Invalid checkpoint ID".to_string());
672→    }
673→    if commit_sha.is_empty() {
674→        return Err("No commit SHA available for this checkpoint".to_string());
675→    }
676→
677→    let repo = git::open_repo(&repo_path)?;
678→    let files = collect_checkpoint_diff(&repo, &commit_sha)?;
679→    if files.is_empty() {
680→        return Ok(semantic_review::RunCheckpointSemanticReviewResponse {
681→            review_run_id: generate_review_run_id(),
682→            annotations: Vec::new(),
683→        });
684→    }
685→
686→    let transcripts = load_sanitized_checkpoint_transcripts(&repo, &checkpoint_id)?;
687→    let prompt = semantic_review::build_prompt(&files, &transcripts);
688→    let raw_text = call_anthropic_semantic_review(&prompt)?;
689→    let parsed = semantic_review::parse_response_text(&raw_text)?;
690→    let annotations = semantic_review::resolve_annotations(&files, parsed);
691→
692→    Ok(semantic_review::RunCheckpointSemanticReviewResponse {
693→        review_run_id: generate_review_run_id(),
694→        annotations,
695→    })
696→}
