 1→import { useEffect, useRef, useCallback } from "react";
 2→import { invoke } from "@tauri-apps/api/core";
 3→
 4→interface GhosttyTerminalProps {
 5→  surfaceId: string | null;
 6→  className?: string;
 7→}
 8→
 9→/**
10→ * Transparent placeholder that positions a native NSView overlay for libghostty.
11→ *
12→ * The actual terminal rendering happens in Metal via libghostty — this div
13→ * just tracks its position/size in the viewport and syncs it to the native layer.
14→ */
15→export function GhosttyTerminal({ surfaceId, className }: GhosttyTerminalProps) {
16→  const containerRef = useRef<HTMLDivElement>(null);
17→  const rafRef = useRef<number>(0);
18→
19→  // Sync the native overlay position to match this div's position in the viewport
20→  const syncOverlay = useCallback(() => {
21→    if (!surfaceId || !containerRef.current) return;
22→
23→    const rect = containerRef.current.getBoundingClientRect();
24→    invoke("ghostty_update_overlay", {
25→      surfaceId,
26→      x: rect.x,
27→      y: rect.y,
28→      width: rect.width,
29→      height: rect.height,
30→    }).catch(console.error);
31→  }, [surfaceId]);
32→
33→  useEffect(() => {
34→    if (!containerRef.current || !surfaceId) return;
35→
36→    // Initial sync
37→    syncOverlay();
38→
39→    // Show the overlay
40→    invoke("ghostty_show_overlay", { surfaceId, visible: true })
41→      .then(() => invoke("ghostty_focus_overlay", { surfaceId }))
42→      .catch(console.error);
43→
44→    // Track resize/reposition
45→    const observer = new ResizeObserver(() => {
46→      cancelAnimationFrame(rafRef.current);
47→      rafRef.current = requestAnimationFrame(syncOverlay);
48→    });
49→    observer.observe(containerRef.current);
50→
51→    // Also sync on scroll (in case the terminal is inside a scrollable container)
52→    const onScroll = () => {
53→      cancelAnimationFrame(rafRef.current);
54→      rafRef.current = requestAnimationFrame(syncOverlay);
55→    };
56→    window.addEventListener("scroll", onScroll, true);
57→
58→    return () => {
59→      observer.disconnect();
60→      window.removeEventListener("scroll", onScroll, true);
61→      cancelAnimationFrame(rafRef.current);
62→
63→      // Hide overlay when component unmounts
64→      invoke("ghostty_show_overlay", { surfaceId, visible: false }).catch(
65→        console.error
66→      );
67→    };
68→  }, [surfaceId, syncOverlay]);
69→
70→  // Click to focus the native terminal
71→  const handleClick = useCallback(() => {
72→    if (surfaceId) {
73→      invoke("ghostty_focus_overlay", { surfaceId }).catch(console.error);
74→    }
75→  }, [surfaceId]);
76→
77→  return (
78→    <div
79→      ref={containerRef}
80→      onClick={handleClick}
81→      className={`h-full w-full ${className ?? ""}`}
82→      style={{
83→        // Transparent so the native Metal view shows through
84→        background: "transparent",
85→        // Prevent the webview from capturing events meant for the native overlay
86→        pointerEvents: surfaceId ? "none" : "auto",
87→      }}
88→    >
89→      {!surfaceId && <div className="h-full w-full" />}
90→    </div>
91→  );
92→}
