  8→  clearPaneAutoLaunch,
  9→  closePaneInTerminalTab,
 10→  closeTerminalTabInWorkspace,
 11→  createTerminalTabInWorkspace,
 12→  resolveAutoLaunchTarget,
 13→  resolveAgentLaunchTarget,
 14→  setActivePaneInTerminalTab,
 15→  setActiveTerminalTabInWorkspace,
 16→  setPaneSession,
 17→  splitActivePaneInTerminalTab,
