 38→function buildSessionLabel(branch: string, agent: string) {
 39→  if (agent === "claude-code") return `Claude - ${branch}`;
 40→  if (agent === "codex") return `Codex - ${branch}`;
 41→  return `Terminal - ${branch}`;
 42→}
