 44→interface TerminalPanelProps {
 45→  height: number;
 46→  tab: Tab;
 47→  workspace: TerminalWorkspace;
 48→  onWorkspaceChange: (update: WorkspaceUpdate) => void;
 49→  onToggle: () => void;
 50→}
 51→
 52→function getActiveTerminalTab(workspace: TerminalWorkspace): TerminalTabState | null {
 53→  return (
 54→    workspace.terminalTabs.find(
 55→      (terminalTab) => terminalTab.id === workspace.activeTerminalTabId
 56→    ) ??
 57→    workspace.terminalTabs[0] ??
 58→    null
 59→  );
 60→}
 61→
 62→export const TerminalPanel = forwardRef<TerminalPanelHandle, TerminalPanelProps>(
 63→  function TerminalPanel({ height, tab, workspace, onWorkspaceChange, onToggle }, ref) {
 64→  const [isLaunching, setIsLaunching] = useState(false);
 65→  const [isDropTarget, setIsDropTarget] = useState(false);
 66→  const [error, setError] = useState<string | null>(null);
 67→  const panelRef = useRef<HTMLDivElement>(null);
 68→  const activeTerminalTab = getActiveTerminalTab(workspace);
 69→  const activePane =
 70→    activeTerminalTab?.panes.find((pane) => pane.id === activeTerminalTab.activePaneId) ??
 71→    activeTerminalTab?.panes[0] ??
 72→    null;
 73→  const activeSurfaceId = activePane?.session?.id ?? null;
 74→
 75→  const isPositionInsidePanel = useCallback((position: { x: number; y: number }) => {
 76→    const rect = panelRef.current?.getBoundingClientRect();
 77→    if (!rect) return false;
 78→
 79→    return (
 80→      position.x >= rect.left &&
 81→      position.x <= rect.right &&
 82→      position.y >= rect.top &&
 83→      position.y <= rect.bottom
 84→    );
 85→  }, []);
 86→
 87→  const sendDroppedImagePaths = useCallback(async (paths: string[]) => {
 88→    if (!activeSurfaceId) return;
 89→
 90→    const text = formatDroppedImagePaths(paths);
 91→    if (!text) return;
 92→
 93→    try {
 94→      await invoke("ghostty_send_text", {
 95→        surfaceId: activeSurfaceId,
 96→        text,
 97→      });
 98→      await invoke("ghostty_focus_overlay", { surfaceId: activeSurfaceId });
 99→    } catch (err) {
100→      console.error("Failed to send dropped paths to terminal:", err);
101→      setError("Could not insert dropped image path into the terminal");
102→    }
103→  }, [activeSurfaceId]);
104→
105→  const focusPane = useCallback(
106→    (terminalTabId: string, paneId: string) => {
107→      const nextWorkspace = setActivePaneInTerminalTab(
108→        setActiveTerminalTabInWorkspace(workspace, terminalTabId),
109→        terminalTabId,
110→        paneId
111→      );
112→      onWorkspaceChange(nextWorkspace);
113→      const pane = nextWorkspace.terminalTabs
114→        .find((terminalTab) => terminalTab.id === terminalTabId)
115→        ?.panes.find((candidate) => candidate.id === paneId);
116→      if (pane?.session) {
117→        invoke("ghostty_focus_overlay", { surfaceId: pane.session.id }).catch(
118→          console.error
119→        );
120→      }
121→    },
122→    [workspace, onWorkspaceChange]
123→  );
124→
125→  const launchTerminal = useCallback(
126→    async (
127→      agent = "terminal",
128→      target?: { terminalTabId?: string; paneId?: string }
129→    ) => {
130→      debugLog(`launchTerminal called: tab.id=${tab.id}, tab.repoPath=${JSON.stringify(tab.repoPath)}, tab.branch=${tab.branch}, isLaunching=${isLaunching}`);
131→
132→      if (!tab.repoPath) {
133→        debugLog("BAIL: tab.repoPath is empty/falsy");
134→        setError("No repository selected — pick a branch from the sidebar");
135→        return "";
136→      }
137→      if (isLaunching) {
138→        debugLog("BAIL: isLaunching=true, already in progress");
139→        return "";
140→      }
141→
142→      let nextWorkspace = workspace;
143→      let terminalTabId = target?.terminalTabId;
144→      let paneId = target?.paneId;
145→
146→      if (!terminalTabId || !paneId) {
147→        const launchTarget = resolveAgentLaunchTarget(nextWorkspace);
148→        if (launchTarget.mode === "create-terminal-tab") {
149→          nextWorkspace = createTerminalTabInWorkspace(nextWorkspace);
150→          const nextTarget = resolveAgentLaunchTarget(nextWorkspace);
151→          if (nextTarget.mode === "create-terminal-tab") {
152→            return "";
153→          }
154→          terminalTabId = nextTarget.terminalTabId;
155→          paneId = nextTarget.paneId;
156→        } else {
157→          terminalTabId = launchTarget.terminalTabId;
158→          paneId = launchTarget.paneId;
159→        }
160→      }
161→
162→      if (!terminalTabId || !paneId) {
163→        return "";
164→      }
165→
166→      nextWorkspace = setActivePaneInTerminalTab(
167→        setActiveTerminalTabInWorkspace(nextWorkspace, terminalTabId),
168→        terminalTabId,
169→        paneId
170→      );
171→      onWorkspaceChange(nextWorkspace);
172→
173→      const targetTab = nextWorkspace.terminalTabs.find(
174→        (terminalTab) => terminalTab.id === terminalTabId
175→      );
176→      const targetPane = targetTab?.panes.find((pane) => pane.id === paneId);
177→
178→      if (targetPane?.session) {
179→        debugLog(`Reusing existing session ${targetPane.session.id} for pane ${paneId}`);
180→        return targetPane.session.id;
181→      }
182→
183→      setError(null);
184→      setIsLaunching(true);
185→      debugLog(`Calling ghostty_create_surface with workingDir=${tab.repoPath}`);
186→      try {
187→        const surfaceId: string = await invoke("ghostty_create_surface", {
188→          workingDir: tab.repoPath,
189→          command: agent === "terminal" ? undefined : agent,
190→        });
191→
192→        debugLog(`ghostty_create_surface returned surfaceId=${surfaceId}`);
193→        const newSession: TermSession = {
194→          id: surfaceId,
195→          agent,
196→          label: buildSessionLabel(tab.branch, agent),
197→        };
198→        onWorkspaceChange((currentWorkspace) =>
199→          setPaneSession(currentWorkspace, terminalTabId, paneId, newSession)
200→        );
201→        return surfaceId;
202→      } catch (err) {
203→        const message = err instanceof Error ? err.message : String(err);
204→        debugLog(`ghostty_create_surface FAILED: ${message}`);
205→        console.error("Failed to create ghostty surface:", err);
206→        setError(`Terminal failed: ${message}`);
207→        return "";
208→      } finally {
209→        setIsLaunching(false);
210→      }
211→    },
212→    [tab.id, tab.repoPath, tab.branch, workspace, isLaunching, onWorkspaceChange]
213→  );
214→
215→  const killPaneSession = useCallback(async (terminalTabId: string, paneId: string) => {
216→    const terminalTab = workspace.terminalTabs.find(
217→      (candidate) => candidate.id === terminalTabId
218→    );
219→    const pane = terminalTab?.panes.find((candidate) => candidate.id === paneId);
220→    if (!pane?.session) return;
221→    try {
222→      await invoke("ghostty_destroy_surface", { surfaceId: pane.session.id });
223→    } catch (err) {
224→      console.error("Failed to destroy surface:", err);
225→    }
226→    onWorkspaceChange((currentWorkspace) =>
227→      setPaneSession(currentWorkspace, terminalTabId, paneId, null)
228→    );
229→  }, [workspace, onWorkspaceChange]);
230→
231→  const closePane = useCallback(async () => {
232→    if (!activeTerminalTab || !activePane || activeTerminalTab.panes.length < 2) return;
233→    await killPaneSession(activeTerminalTab.id, activePane.id);
234→    onWorkspaceChange((currentWorkspace) =>
235→      closePaneInTerminalTab(currentWorkspace, activeTerminalTab.id, activePane.id)
236→    );
237→  }, [activeTerminalTab, activePane, killPaneSession, onWorkspaceChange]);
238→
239→  const closeTerminalTab = useCallback(async (terminalTabId: string) => {
240→    const terminalTab = workspace.terminalTabs.find(
241→      (candidate) => candidate.id === terminalTabId
242→    );
243→    if (!terminalTab) return;
244→
245→    for (const pane of terminalTab.panes) {
246→      if (pane.session) {
247→        try {
248→          await invoke("ghostty_destroy_surface", { surfaceId: pane.session.id });
249→        } catch (err) {
250→          console.error("Failed to destroy surface:", err);
251→        }
252→      }
253→    }
254→
255→    onWorkspaceChange((currentWorkspace) =>
256→      closeTerminalTabInWorkspace(currentWorkspace, terminalTabId)
257→    );
258→  }, [workspace, onWorkspaceChange]);
259→
260→  useImperativeHandle(ref, () => ({
261→    async launchSession(options = {}) {
262→      const agent = options.agent ?? "terminal";
263→      const surfaceId = await launchTerminal(agent);
264→      if (!surfaceId) return;
265→      if (!options.prompt) return;
266→
267→      // Small delay for PTY initialization, then send the prompt
268→      setTimeout(async () => {
269→        try {
270→          await invoke("ghostty_send_text", {
271→            surfaceId,
272→            text: options.prompt + "\n",
273→          });
274→        } catch (err) {
275→          console.error("Failed to send prompt to terminal:", err);
276→        }
277→      }, 300);
278→    },
279→  }), [launchTerminal]);
280→
281→  useEffect(() => {
282→    if (!tab.repoPath || isLaunching) return;
283→
284→    const target = resolveAutoLaunchTarget(workspace);
285→    if (!target?.terminalTabId) return;
286→
287→    onWorkspaceChange((currentWorkspace) =>
288→      clearPaneAutoLaunch(currentWorkspace, target.terminalTabId!, target.paneId)
289→    );
290→    void launchTerminal("terminal", target);
291→  }, [tab.repoPath, workspace, isLaunching, launchTerminal, onWorkspaceChange]);
292→
293→  useEffect(() => {
294→    let cancelled = false;
295→    let unlisten: (() => void) | undefined;
296→
297→    getCurrentWindow()
298→      .onDragDropEvent((event) => {
299→        if (cancelled) return;
300→
301→        if (event.payload.type === "leave") {
302→          setIsDropTarget(false);
303→          return;
304→        }
305→
306→        const isInside = isPositionInsidePanel(event.payload.position);
307→        if (event.payload.type === "enter" || event.payload.type === "over") {
308→          setIsDropTarget(isInside);
309→          return;
310→        }
311→
312→        setIsDropTarget(false);
313→        if (!isInside) return;
314→        void sendDroppedImagePaths(event.payload.paths);
315→      })
316→      .then((cleanup) => {
317→        if (cancelled) {
318→          cleanup();
319→          return;
320→        }
321→        unlisten = cleanup;
322→      })
323→      .catch(console.error);
324→
325→    return () => {
326→      cancelled = true;
327→      setIsDropTarget(false);
328→      unlisten?.();
329→    };
330→  }, [isPositionInsidePanel, sendDroppedImagePaths]);
331→
332→  return (
333→    <div
334→      ref={panelRef}
335→      className="relative flex shrink-0 flex-col bg-[#0a0a0a]"
336→      style={{ height }}
337→    >
338→      <div className="flex items-center gap-2 border-t border-border bg-bg-raised px-3 py-1.5">
339→        <div className="flex min-w-0 flex-1 items-center gap-1 overflow-x-auto">
340→          {workspace.terminalTabs.map((terminalTab) => {
341→            const isActive = terminalTab.id === activeTerminalTab?.id;
342→            return (
343→              <div
344→                key={terminalTab.id}
345→                className={`flex items-center rounded-md border ${
346→                  isActive
347→                    ? "border-accent bg-accent-bg/40 text-accent-fg"
348→                    : "border-border-subtle text-fg-subtle"
349→                }`}
350→              >
351→                <button
352→                  onClick={() =>
353→                    onWorkspaceChange(
354→                      setActiveTerminalTabInWorkspace(workspace, terminalTab.id)
355→                    )
356→                  }
357→                  className="px-2.5 py-1 text-[11px]"
358→                >
359→                  {terminalTab.title}
360→                </button>
361→                <button
362→                  onClick={() => void closeTerminalTab(terminalTab.id)}
363→                  className="px-2 py-1 text-[11px] hover:text-red"
