167→/// Launch an agent in an external Ghostty window (for "Send to Agent" from review bar).
168→pub fn launch_ghostty_agent(repo_path: &str, agent: &str, prompt: &str) -> Result<(), String> {
169→    use std::process::Command;
170→
171→    let cli = match agent {
172→        "claude-code" => "claude",
173→        "codex" => "codex",
174→        other => other,
175→    };
176→
177→    // Write prompt to a temp file, then pipe it into the agent CLI
178→    let tmp = std::env::temp_dir().join(format!("entire-prompt-{}.txt", uuid_v4()));
179→    std::fs::write(&tmp, prompt).map_err(|e| format!("Failed to write prompt: {}", e))?;
180→
181→    let shell_cmd = format!(
182→        "cd {} && cat {} | {} ; rm -f {}",
183→        shell_escape(repo_path),
184→        shell_escape(&tmp.to_string_lossy()),
185→        cli,
186→        shell_escape(&tmp.to_string_lossy()),
187→    );
188→
189→    Command::new("ghostty")
190→        .args(["-e", "sh", "-c", &shell_cmd])
191→        .spawn()
192→        .map_err(|e| format!("Failed to launch ghostty: {}", e))?;
193→
194→    Ok(())
195→}
196→
197→fn shell_escape(s: &str) -> String {
198→    format!("'{}'", s.replace('\'', "'\\''"))
199→}
