542→pub(super) fn system_clipboard_text() -> Option<String> {
543→    let pasteboard = NSPasteboard::generalPasteboard();
544→    pasteboard
545→        .stringForType(unsafe { NSPasteboardTypeString })
546→        .map(|text| text.to_string())
547→}
