148→/// Reposition the native overlay to match the terminal panel's position in the webview.
149→///
150→/// Coordinates are in CSS pixels with top-left origin (matching getBoundingClientRect).
151→#[tauri::command]
152→pub fn ghostty_update_overlay(
153→    surface_id: String,
154→    x: f64,
155→    y: f64,
156→    width: f64,
157→    height: f64,
158→    state: State<'_, Mutex<super::GhosttyState>>,
159→) -> Result<(), String> {
160→    let gs = state.lock().map_err(|_| "State lock error".to_string())?;
161→    let entry = gs
162→        .surfaces
163→        .get(&surface_id)
164→        .ok_or_else(|| format!("Surface not found: {}", surface_id))?;
165→
166→    // Update the NSView frame to match
167→    entry.overlay.update_frame(x, y, width, height);
168→
169→    // Also update the libghostty surface size (in physical pixels for Metal)
170→    let scale = 2.0; // TODO: get actual scale factor
171→    entry
172→        .surface
173→        .set_size((width * scale) as u32, (height * scale) as u32);
174→
175→    Ok(())
176→}
