236→/// Send text to the terminal surface (for agent prompt injection).
237→#[tauri::command]
238→pub fn ghostty_send_text(
239→    surface_id: String,
240→    text: String,
241→    state: State<'_, Mutex<super::GhosttyState>>,
242→) -> Result<(), String> {
243→    let gs = state.lock().map_err(|_| "State lock error".to_string())?;
244→    let entry = gs
245→        .surfaces
246→        .get(&surface_id)
247→        .ok_or_else(|| format!("Surface not found: {}", surface_id))?;
248→
249→    entry.surface.send_text(&text);
250→    Ok(())
251→}
