 15→fn debug_log(msg: &str) {
 16→    use std::io::Write;
 17→
 18→    let timestamp = std::time::SystemTime::now()
 19→        .duration_since(std::time::UNIX_EPOCH)
 20→        .unwrap_or_default();
 21→    let line = format!(
 22→        "[{}.{:03}] {}\n",
 23→        timestamp.as_secs(),
 24→        timestamp.subsec_millis(),
 25→        msg
 26→    );
 27→    if let Ok(mut f) = std::fs::OpenOptions::new()
 28→        .create(true)
 29→        .append(true)
 30→        .open("/tmp/entire-terminal-debug.log")
 31→    {
 32→        let _ = f.write_all(line.as_bytes());
 33→    }
 34→}
