 1→fn main() {
 2→    // Match libghostty's minimum deployment target to avoid linker warnings
 3→    println!("cargo:REDACTED.0");
 4→
 5→    tauri_build::build();
 6→
 7→    // Link libghostty and required macOS frameworks
 8→    let vendor_dir = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"))
 9→        .join("vendor")
10→        .join("ghostty");
11→
12→    println!("cargo:rustc-link-search=native={}", vendor_dir.display());
13→    println!("cargo:rustc-link-lib=static=ghostty");
14→
15→    // C++ standard library required by glslang (shader compiler) in libghostty
16→    println!("cargo:rustc-link-lib=c++");
17→
18→    // macOS frameworks required by libghostty's Metal renderer
19→    println!("cargo:rustc-link-lib=framework=Metal");
20→    println!("cargo:rustc-link-lib=framework=MetalKit");
21→    println!("cargo:rustc-link-lib=framework=AppKit");
22→    println!("cargo:rustc-link-lib=framework=QuartzCore");
23→    println!("cargo:rustc-link-lib=framework=CoreGraphics");
24→    println!("cargo:rustc-link-lib=framework=IOSurface");
25→    println!("cargo:rustc-link-lib=framework=Foundation");
26→
27→    // Rerun if the static library changes
28→    println!("cargo:rerun-if-changed=vendor/ghostty/libghostty.a");
29→    println!("cargo:rerun-if-changed=vendor/ghostty/ghostty.h");
