  1→import { useState, useCallback, useImperativeHandle, forwardRef, useEffect, useRef } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import { getCurrentWindow } from "@tauri-apps/api/window";
  4→import { GhosttyTerminal } from "./GhosttyTerminal";
  5→import { getPaneChrome } from "./chrome";
  6→import { formatDroppedImagePaths } from "./drop-paths";
  7→import {
  8→  clearPaneAutoLaunch,
  9→  closePaneInTerminalTab,
 10→  closeTerminalTabInWorkspace,
 11→  createTerminalTabInWorkspace,
 12→  resolveAutoLaunchTarget,
 13→  resolveAgentLaunchTarget,
 14→  setActivePaneInTerminalTab,
 15→  setActiveTerminalTabInWorkspace,
 16→  setPaneSession,
 17→  splitActivePaneInTerminalTab,
 18→  type TerminalTabState,
 19→  type TerminalWorkspace,
 20→  type WorkspaceUpdate,
 21→} from "./workspace";
