use portable_pty::{native_pty_system, CommandBuilder, PtySize};
use serde::Serialize;
use std::collections::HashMap;
use std::io::{Read, Write};
use std::sync::{Arc, Mutex};

#[derive(Debug, Serialize, Clone)]
pub struct PtySessionInfo {
    pub id: String,
    pub agent: String,
    pub repo_path: String,
}

pub struct PtyManager {
    sessions: Arc<Mutex<HashMap<String, PtySession>>>,
}

struct PtySession {
    writer: Box<dyn Write + Send>,
    master: Box<dyn portable_pty::MasterPty + Send>,
    _child: Box<dyn portable_pty::Child + Send + Sync>,
    #[allow(dead_code)]
    info: PtySessionInfo,
}

impl PtyManager {
    pub fn new() -> Self {
        Self {
            sessions: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    pub fn spawn(
        &self,
        agent: &str,
        repo_path: &str,
        event_emitter: impl Fn(String, Vec<u8>) + Send + 'static,
    ) -> Result<String, String> {
        let pty_system = native_pty_system();

        let pair = pty_system
            .openpty(PtySize {
                rows: 24,
                cols: 80,
                pixel_width: 0,
                pixel_height: 0,
            })
            .map_err(|e| format!("Failed to open PTY: {}", e))?;

        let cmd = match agent {
            "claude-code" => {
                let mut cmd = CommandBuilder::new("claude");
                cmd.cwd(repo_path);
                cmd
            }
            "codex" => {
                let mut cmd = CommandBuilder::new("codex");
                cmd.cwd(repo_path);
                cmd
            }
            _ => return Err(format!("Unknown agent: {}", agent)),
        };

        let child = pair
            .slave
            .spawn_command(cmd)
            .map_err(|e| format!("Failed to spawn: {}", e))?;

        let session_id = uuid_v4();
        let writer = pair
            .master
            .take_writer()
            .map_err(|e| format!("Failed to get writer: {}", e))?;

        let info = PtySessionInfo {
            id: session_id.clone(),
            agent: agent.to_string(),
            repo_path: repo_path.to_string(),
        };

        // Spawn reader thread to stream output
        let mut reader = pair
            .master
            .try_clone_reader()
            .map_err(|e| format!("Failed to clone reader: {}", e))?;

        let sid = session_id.clone();
        std::thread::spawn(move || {
            let mut buf = [0u8; 4096];
            loop {
                match reader.read(&mut buf) {
                    Ok(0) => break,
                    Ok(n) => {
                        event_emitter(sid.clone(), buf[..n].to_vec());
                    }
                    Err(_) => break,
                }
            }
        });

        let session = PtySession {
            writer,
            master: pair.master,
            _child: child,
            info,
        };

        self.sessions
            .lock()
            .map_err(|_| "Lock error".to_string())?
            .insert(session_id.clone(), session);

        Ok(session_id)
    }

    pub fn write(&self, session_id: &str, data: &[u8]) -> Result<(), String> {
        let mut sessions = self
            .sessions
            .lock()
            .map_err(|_| "Lock error".to_string())?;
        let session = sessions
            .get_mut(session_id)
            .ok_or_else(|| "Session not found".to_string())?;
        session
            .writer
            .write_all(data)
            .map_err(|e| format!("Write error: {}", e))
    }

    pub fn resize(&self, session_id: &str, cols: u16, rows: u16) -> Result<(), String> {
        let sessions = self
            .sessions
            .lock()
            .map_err(|_| "Lock error".to_string())?;
        let session = sessions
            .get(session_id)
            .ok_or_else(|| "Session not found".to_string())?;
        session
            .master
            .resize(PtySize {
                rows,
                cols,
                pixel_width: 0,
                pixel_height: 0,
            })
            .map_err(|e| format!("Resize error: {}", e))
    }

    pub fn kill(&self, session_id: &str) -> Result<(), String> {
        let mut sessions = self
            .sessions
            .lock()
            .map_err(|_| "Lock error".to_string())?;
        sessions.remove(session_id);
        Ok(())
    }
}

fn uuid_v4() -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    let now = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default();
    format!("pty-{}-{}", now.as_secs(), now.subsec_nanos())
}

/// Launch an agent in an external Ghostty window (for "Send to Agent" from review bar).
pub fn launch_ghostty_agent(repo_path: &str, agent: &str, prompt: &str) -> Result<(), String> {
    use std::process::Command;

    let cli = match agent {
        "claude-code" => "claude",
        "codex" => "codex",
        other => other,
    };

    // Write prompt to a temp file, then pipe it into the agent CLI
    let tmp = std::env::temp_dir().join(format!("entire-prompt-{}.txt", uuid_v4()));
    std::fs::write(&tmp, prompt).map_err(|e| format!("Failed to write prompt: {}", e))?;

    let shell_cmd = format!(
        "cd {} && cat {} | {} ; rm -f {}",
        shell_escape(repo_path),
        shell_escape(&tmp.to_string_lossy()),
        cli,
        shell_escape(&tmp.to_string_lossy()),
    );

    Command::new("ghostty")
        .args(["-e", "sh", "-c", &shell_cmd])
        .spawn()
        .map_err(|e| format!("Failed to launch ghostty: {}", e))?;

    Ok(())
}

fn shell_escape(s: &str) -> String {
    format!("'{}'", s.replace('\'', "'\\''"))
}
